function slug(value: string): string {
  return value.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
}

export function createBossmannHousePackage(id: string, title: string, defaultArea: number, defaultFloorCount: number): RenovationPackage {
  const rows = HOUSE_ROWS[id] ?? HOUSE_ROWS['1e'];
  const grouped = new Map<string, SourceRow[]>();
  rows.forEach((row) => {
    const category = row[0];
    grouped.set(category, [...(grouped.get(category) ?? []), row]);
  });

  return {
    id,
    title,
    defaultArea,
    defaultFloorCount,
    categories: Array.from(grouped, ([categoryTitle, categoryRows], categoryIndex) => {
      const meta = CATEGORY_META[categoryTitle] ?? CATEGORY_META['Weitere Positionen'];
      const sectionRows = new Map<ProductSeed['type'], SourceRow[]>();
      categoryRows.forEach((row) => {
        const type = row[5];
        sectionRows.set(type, [...(sectionRows.get(type) ?? []), row]);
      });

      return {
        id: meta.id,
        title: categoryTitle,
        lead: meta.lead,
        collapsedByDefault: categoryIndex > 0,
        subsections: Array.from(sectionRows, ([type, typedRows]) => {
          const sectionId = type === 'service' ? 'execution' : type === 'material' ? 'material' : 'extras';
          const sectionTitle = type === 'service' ? 'Art der Ausfuehrung' : type === 'material' ? 'Material' : 'Extra Positionen';
          return {
            id: sectionId,
            title: sectionTitle,
            type,
            products: typedRows.map((row, rowIndex) => createProduct(meta.id, sectionId, {
              id: `bossmann-${slug(row[6])}-${rowIndex}`,
              title: row[1],
              sku: row[6],
              basePrice: row[2],
              unit: row[3],
              baseQuantity: row[4],
              type: row[5],
              enabled: true,
              optional: false,
              description: 'Standardposition fuer das Haussanierungsangebot.',
            })),
          };
        }),
      };
    }),
  };
}
